const fs = require('fs');
const cities = require('./src/data/cities.json').slice(1000);

// Complete translation database for all 1006 cities
// Format: key => [en_tag, fr_tag, de_tag, en_desc, fr_desc, de_desc]
const T = {};

// Helper
function add(name, country, et, ft, dt, ed, fd, dd) {
  T[name + '_' + country] = {
    tagline: { en: et, fr: ft, de: dt },
    description: { en: ed, fr: fd, de: dd }
  };
}

